={{ (() => {
  const run = $('Get Run').item?.json ?? {};
  const stages = run.stages ?? {};
  const clone = (value) => (value && typeof value === 'object' ? { ...value } : {});
  const ideaStage = clone(stages.idea_generation);
  if (!ideaStage.status) { ideaStage.status = 'completed'; }
  const screenplay = $('Parse Screenplay Output').item.json.screenplay;
  const videoId = $('Parse Screenplay Output').item.json.videoId;
  const screenplayStage = { ...clone(stages.screenplay), status: 'completed', output: { screenplay, videoId, completedAt: new Date().toISOString() } };
  const videoStage = { ...clone(stages.video_generation), status: 'running' };
  const publishingStage = clone(stages.publishing);
  if (!publishingStage.status) { publishingStage.status = 'pending'; }

  const mergedOutput = { ...(run.output ?? {}), screenplay: screenplay };

  return {
    status: 'running',
    currentStage: 'video_generation',
    stages: {
      idea_generation: ideaStage,
      screenplay: screenplayStage,
      video_generation: videoStage,
      publishing: publishingStage
    },
    output: mergedOutput
  };
})() }}

