parameters.jsCode:
// Parse AI Agent output to extract structured screenplay
const rawOutput = $json.output ?? $json.result ?? $json.response ?? $json;
let parsed = null;

// Try to parse JSON from string output
if (typeof rawOutput === 'string') {
  try {
    // Extract JSON from markdown code blocks if present
    const jsonMatch = rawOutput.match(/```(?:json)?\s*([\s\S]*?)\s*```/) || rawOutput.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      parsed = JSON.parse(jsonMatch[1] || jsonMatch[0]);
    } else {
      parsed = JSON.parse(rawOutput);
    }
  } catch (e) {
    console.warn('Failed to parse JSON from AI output:', e);
    parsed = { screenplay: { title: 'Untitled', scenes: [], totalDuration: 60, triggerWords: [] }, videoId: $('When Called').item.json.ideaId };
  }
} else if (typeof rawOutput === 'object') {
  parsed = rawOutput;
}

// Ensure screenplay structure exists
const screenplay = parsed?.screenplay || {
  title: parsed?.title || 'Untitled Screenplay',
  scenes: Array.isArray(parsed?.scenes) ? parsed.scenes : [],
  totalDuration: parsed?.totalDuration || parsed?.duration || 60,
  triggerWords: Array.isArray(parsed?.triggerWords) ? parsed.triggerWords : []
};

// Ensure videoId is present
const videoId = parsed?.videoId || $('When Called').item.json.ideaId || null;

// Normalize scenes array
const normalizedScenes = screenplay.scenes.map((scene, index) => ({
  sceneNumber: scene.sceneNumber || index + 1,
  duration: scene.duration || 10,
  dialogue: scene.dialogue || '',
  actions: Array.isArray(scene.actions) ? scene.actions : [],
  soundEffects: Array.isArray(scene.soundEffects) ? scene.soundEffects : [],
  cameraAngle: scene.cameraAngle || 'medium'
}));

return {
  json: {
    screenplay: {
      ...screenplay,
      scenes: normalizedScenes
    },
    videoId: videoId,
    rawOutput: rawOutput
  }
};

const payload = $json?.workflowRun ?? $json?.data?.workflowRun ?? null;
if (!payload) {
  throw new Error('Workflow run payload missing from API response.');
}

const metadata = {};
if (payload.input && typeof payload.input === 'object') {
  if (payload.input.metadata && typeof payload.input.metadata === 'object') {
    Object.assign(metadata, payload.input.metadata);
  }
  if (payload.input.turn && typeof payload.input.turn === 'object' && payload.input.turn.metadata && typeof payload.input.turn.metadata === 'object') {
    Object.assign(metadata, payload.input.turn.metadata);
  }
  if (payload.input.projectSlug && typeof payload.input.projectSlug === 'string' && !metadata.projectSlug) {
    metadata.projectSlug = payload.input.projectSlug;
  }
}
if (!metadata.projectSlug && typeof payload.projectId === 'string') {
  metadata.projectSlug = payload.projectId;
}

const normalized = {
  ...payload,
  run_id: payload.id,
  project_id: payload.projectId ?? null,
  projectId: payload.projectId ?? null,
  session_id: payload.sessionId ?? null,
  sessionId: payload.sessionId ?? null,
  input: payload.input ?? {},
  metadata,
};

return [{ json: normalized }];

const screenplay = $('Parse Screenplay Output').item.json.screenplay;
const videoId = $('Parse Screenplay Output').item.json.videoId;

return {
  json: {
    screenplay,
    videoId,
    status: 'completed'
  }
};

